// // This module implements a 8-bit counter that decrements from 255 to 0. The counter increments on each clock cycle when enabled and rolls over to 255 when it reaches 0. A reset signal sets the counter to 255.
module timer_8bit(  
    input clk,  
    input rst,  
    input en,  
    output reg [7:0] count  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            count <= 8'b0;  
        end else if (en) begin  
            count <= (count == 8'b11111111) ? 8'b0 : count + 1;  
        end  
    end  
endmodule
